const fechaCot = this.frm_gen_fecha_cotizacion; //"YYYY-MM-DD"
if (!fechaCot) return null; 

const fecha = new Date(`${fechaCot}T00:00:00`);

fecha.setDate(fecha.getDate() + 30);

return fecha.toISOString().slice(0, 10);

const inicio = this.frm_inicio_vigencia; // fecha seleccionada por usuario (YYYY-MM-DD)
const minima = this.frm_inicio_vigencia_minima; // fecha mínima permitida (YYYY-MM-DD)

if (!inicio || !minima) return inicio;

const inicioDate = new Date(`${inicio}T00:00:00`);
const minimaDate = new Date(`${minima}T00:00:00`);

const MS_PER_DAY = 24 * 60 * 60 * 1000;
const diffDays = Math.floor((inicioDate - minimaDate) / MS_PER_DAY);

if (diffDays > 30) {
  console.warn(`⛔ La fecha seleccionada (${inicio}) supera los 30 días desde ${minima}.`);
  setTimeout(() => {
    const modalComponent = document.querySelector('[custom-css-selector="btn_preventivo"]');
    if (!modalComponent || !modalComponent.__vue__) return;

    const vueInstance = modalComponent.__vue__;
    vueInstance.$root.$bvModal.show('modal_fecha_invalida'); // Este es el ID del modal
  }, 300);

  return null; // Bloqueamos el flujo si la fecha es inválida
}

return this.frm_inicio_vigencia;

const s = (this.frm_cot_fecha_inicio_vigencia ?? "").toString().trim();
const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
if (!m) return null; 

let dt = new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));

dt.setDate(dt.getDate() + 364);

const y = dt.getFullYear();
const mo = String(dt.getMonth() + 1).padStart(2, "0");
const d  = String(dt.getDate()).padStart(2, "0");
return `${y}-${mo}-${d}`;

(function () {
  const sel = '[selector="moneda-cop"] input[name="frm_ingresos_operaciones_anuales"]';
  const el = document.querySelector(sel);
  if (!el) return;

  const toCOP = () => {
    const v = el.value || '';
    // Quita sufijo moneda conocido y coloca COP
    el.value = v.replace(/\s*(ALL|USD|EUR|COP)?\s*$/i, '') + ' COP';
  };

  // Corrige cuando el usuario termina de escribir o el formateador actúa
  el.addEventListener('blur', toCOP);
  el.addEventListener('change', toCOP);
  el.addEventListener('input', () => {
    // si vuelve a aparecer ALL mientras escribe, lo corrige al vuelo
    if (/\sALL$/i.test(el.value)) toCOP();
  });

  // “Keep-alive” por si el framework reinyecta ALL después de eventos
  const id = setInterval(() => {
    if (!document.body.contains(el)) return clearInterval(id);
    if (/\sALL$/i.test(el.value)) toCOP();
  }, 400);

  // Primera corrección inmediata
  setTimeout(toCOP, 0);
})();

const toDate = (s) => s ? new Date(`${s}T00:00:00`) : null;
const fmt = (d) => d ? [
  String(d.getDate()).padStart(2,'0'),
  String(d.getMonth()+1).padStart(2,'0'),
  d.getFullYear()
].join('/') : '—';

const vStr   = this.frm_cot_fecha_inicio_vigencia;
const minStr = this.frm_cot_fecha_inicio_vigencia_minima;
const maxStr = this.frm_cot_fecha_inicio_vigencia_maxima;

const v   = toDate(vStr);
const min = toDate(minStr);
const max = toDate(maxStr);

setTimeout(() => {
  const input = document.querySelector('input[name="frm_cot_fecha_inicio_vigencia"]');
  if (input) {
    if (minStr) input.setAttribute('min', minStr);
    if (maxStr) input.setAttribute('max', maxStr);
  }
}, 0);

if (!v || !min || !max) {
  return this.frm_cot_fecha_inicio_vigencia ?? null;
}

const outOfRange = (v < min) || (v > max);

setTimeout(() => {
  const input = document.querySelector('input[name="frm_cot_fecha_inicio_vigencia"]');
  const group = input?.closest('.form-group');

  if (group) {
    const prev = group.querySelector('.invalid-feedback');
    if (prev) prev.remove();
  }
  input?.classList.remove('is-invalid');

  if (outOfRange) {
    if (input && !input.classList.contains('is-invalid')) input.classList.add('is-invalid');
    if (group && !group.querySelector('.invalid-feedback')) {
      const msg = document.createElement('div');
      msg.className = 'invalid-feedback d-block';
      msg.innerHTML = `<div>La fecha debe estar entre ${fmt(min)} y ${fmt(max)}.</div>`;
      group.insertBefore(msg, group.querySelector('small.form-text'));
    }

    const MODAL_ID = 'modal_fecha_invalida';
    const BTN_SEL  = '[custom-css-selector="btn_preventivo"]';
    const now = Date.now();
    window.__iv_lastModalAt = window.__iv_lastModalAt || 0;
    if ((now - window.__iv_lastModalAt) > 600) {
      const boton = document.querySelector(BTN_SEL);
      if (boton?.__vue__?.$root?.$bvModal) boton.__vue__.$root.$bvModal.show(MODAL_ID);
      window.__iv_lastModalAt = now;
    }
  }
}, 250);

if (outOfRange) return null;
return this.frm_cot_fecha_inicio_vigencia;

const fechaCot = this.frm_gen_fecha_cotizacion;
if (!fechaCot) return null; 

const fecha = new Date(`${fechaCot}T00:00:00`);

fecha.setDate(fecha.getDate() + 31);

return fecha.toISOString().slice(0, 10);

setTimeout(() => {
  const proyectados = parseFloat(this.frm_cot_ingresos_proyectados_anuales) || 0;
  const operaciones = parseFloat(this.frm_cot_ingresos_operaciones_anuales) || 0;

  const inputProyectados = document.querySelector('input[name="frm_cot_ingresos_proyectados_anuales"]');
  const contenedorFormGroup = inputProyectados?.closest('.form-group');

  const maximoPermitido = operaciones * 1.20;

  //console.log("proyectados", proyectados)
  //console.log("operaciones", operaciones)
  //console.log("maximoPermitido", maximoPermitido)

  if (proyectados > maximoPermitido && operaciones > 0) {
    if (inputProyectados && !inputProyectados.classList.contains('is-invalid')) {
      inputProyectados.classList.add('is-invalid');
    }

    if (contenedorFormGroup && !contenedorFormGroup.querySelector('.invalid-feedback')) {
      const errorDiv = document.createElement('div');
      errorDiv.className = 'invalid-feedback d-block';
      errorDiv.innerHTML = '<div>Los ingresos proyectados no deben superar el 20% de los ingresos operacionales anuales.</div>';
      contenedorFormGroup.insertBefore(errorDiv, contenedorFormGroup.querySelector('small.form-text'));
    }

    const boton = document.querySelector('[custom-css-selector="btn_preventivo_proyectadoAnual"]');
    if (boton && boton.__vue__) {
      boton.__vue__.$root.$bvModal.show('modal_ingresos_incorrectos');
    }
  } else {
    if (inputProyectados?.classList.contains('is-invalid')) {
      inputProyectados.classList.remove('is-invalid');
    }

    if (contenedorFormGroup) {
      const mensajeError = contenedorFormGroup.querySelector('.invalid-feedback');
      if (mensajeError) mensajeError.remove();
    }
  }
}, 600);

// Return final (por fuera del setTimeout)
const proyectados = parseFloat(this.frm_cot_ingresos_proyectados_anuales) || 0;
const operaciones = parseFloat(this.frm_cot_ingresos_operaciones_anuales) || 0;
const maximoPermitido = operaciones * 0.20;

if (proyectados > maximoPermitido && operaciones > 0) {
  return null;
}

return this.frm_cot_ingresos_proyectados_anuales;

