/* Contenedor general del modal de fecha */
[selector="contenido-modal-fecha"] {
  padding: 22px 18px 0px;
  margin: -25px 0px -19px 0px;
  font-family: "Segoe UI", Roboto, sans-serif;
  background-color: #ffffff;
  color: #2c2c2c;
}

/* Ícono decorativo para fecha */
[selector="contenido-modal-fecha"] .icono-fecha::before {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f073"; /* fa-calendar-alt */
  font-size: 2.8rem;
  color: #dc3545; /* Rojo de advertencia */
  display: inline-block;
  margin-bottom: -6px;
}

/* Título */
[selector="contenido-modal-fecha"] .titulo-fecha {
  font-size: 1.3rem;
  font-weight: 600;
  color: #dc3545;
}

/* Texto del cuerpo */
[selector="contenido-modal-fecha"] .texto-fecha {
  font-size: 1.05rem;
  line-height: 1.6;
  color: #333333;
}

/* Texto secundario */
[selector="contenido-modal-fecha"] .texto-fecha-sub {
  font-size: 14px;
  padding-top: 5px;
}

/*Modal Proyectado Anual*/

